#include<stdio.h>
#define m 1000000007

long int power(long int a,long int b)
{
    long int ans=1;
    if(b==0)
        return 1;
    while(b>0) {
        if (b % 2 != 0)
            ans= ans * a;
        a = a * a;
        b = b / 2;
    }
    return ans;
}

int main()
{
    long int n,i=0,index=0;
    scanf("%ld",&n);
    while(n>0)
    {
        int rem=n%10;
        if(rem==4)
            index+=power(2,i);
        else
            index+=power(2,i+1);
        n=n/10;
        i++;
    }
    printf("%ld\n",index);
}

