fn main() {
    let mut bin = String::new();
    let mut input = WordReader::from_stdin(&mut bin);

    let n = input.s().into_bytes();
    let sol = (1..).flat_map(|a| iter::repeat(a).take(1<<a).enumerate().map(|(b,a)| {
        let mut v = vec![b'0'; a];
        let mut b = b;
        for x in v.iter_mut().rev() {
            *x = b'4' + (3 * (b % 2)) as u8;
            b /= 2;
        }
        v
    })).position(|x| x == n).unwrap() + 1;
    println!("{}", sol);
